// Get recommendations based on detected domain
function getRecommendations(quizDomain, cvDomain) {
    const d = (quizDomain || cvDomain || "").toLowerCase();
    if (d.includes("cyber") || d.includes("security")) return DOMAIN_RECOMMENDATIONS["cybersecurity"];
    if (d.includes("cloud") || d.includes("azure") || d.includes("aws") || d.includes("gcp")) return DOMAIN_RECOMMENDATIONS["cloud"];
    if (d.includes("ai") || d.includes("machine learning") || d.includes("deep learning")) return DOMAIN_RECOMMENDATIONS["ai"];
    if (d.includes("software") || d.includes("java") || d.includes("web") || d.includes("dev")) return DOMAIN_RECOMMENDATIONS["software"];
    return DOMAIN_RECOMMENDATIONS["data"]; // default
}
